### TC2: Concurrent initialization race
```rust
#[test]
fn test_concurrent_init_no_race() {
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::thread;

    static INIT_COUNT: AtomicUsize = AtomicUsize::new(0);

    let handles: Vec<_> = (0..10).map(|_| {
        thread::spawn(|| {
            let _ = get_or_init_two_tier_bridge();
            // Track if this thread triggered init (tricky to measure)
        })
    }).collect();

    for h in handles {
        h.join().unwrap();
    }

    // Verify all threads got the same bridge
    // (Actual init count check requires instrumentation)
}
```

### TC3: Initialization under contention
```rust
#[test]
fn test_init_under_contention() {
    use std::sync::Barrier;

    let barrier = Arc::new(Barrier::new(10));
    let handles: Vec<_> = (0..10).map(|_| {
        let b = barrier.clone();
        thread::spawn(move || {
            b.wait();  // Synchronize start
            get_or_init_two_tier_bridge()
        })
    }).collect();

    let bridges: Vec<_> = handles.into_iter()
        .map(|h| h.join().unwrap())
        .collect();

    // All should be same Arc
    for bridge in &bridges[1..] {
        assert!(Arc::ptr_eq(&bridges[0], bridge));
    }
}
```

### TC4: Init timing measurement
```rust
#[test]
fn test_init_timing() {
    // First call may take time (embedder init)
    let start1 = Instant::now();
    let _ = get_or_init_two_tier_bridge();
    let first_duration = start1.elapsed();

    // Second call should be instant
    let start2 = Instant::now();
    let _ = get_or_init_two_tier_bridge();
    let second_duration = start2.elapsed();

    assert!(second_duration < Duration::from_micros(100),
        "cached access should be <100µs, was {:?}", second_duration);
}
```

