#[test]
fn test_score_blending_math() {
    let fast_scores = vec![0.9, 0.7, 0.5];
    let quality_scores = vec![0.5, 0.9, 0.7];
    let weight = 0.7;

    let blended = blend_scores(&fast_scores, &quality_scores, weight);

    // Doc 0: 0.3*0.9 + 0.7*0.5 = 0.27 + 0.35 = 0.62 (normalized)
    // Doc 1: 0.3*0.7 + 0.7*0.9 = 0.21 + 0.63 = 0.84 (normalized)
    // Doc 2: 0.3*0.5 + 0.7*0.7 = 0.15 + 0.49 = 0.64 (normalized)

    // After normalization, doc 1 should have highest blended score
    let max_idx = blended.iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .map(|(i, _)| i);
    assert_eq!(max_idx, Some(1), "doc 1 should have highest blended score");
}
