 {"id":"br-2tnl.5.10.7","title":"T5.10.7: E2E test script for two-tier search hardening","description":"## Objective

End-to-end test script that validates the complete two-tier search hardening:
1. Thread-safe initialization
2. Quality embedding fallback
3. Progressive refinement

## Script: tests/e2e/two_tier_hardening.sh

```bash
#!/usr/bin/env bash
# E2E Test: Two-Tier Search Hardening
# Tests thread-safe init, quality fallback, and progressive refinement
#
# Usage: ./tests/e2e/two_tier_hardening.sh [--verbose]
#
# Exit codes:
#   0 - All tests passed
#   1 - Test failure
#   2 - Setup failure

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
LOG_DIR="${PROJECT_ROOT}/test_logs/two_tier_hardening_$(date +%Y%m%d_%H%M%S)"
VERBOSE="${1:-}"

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

log_info() { echo -e "${BLUE}[INFO]${NC} $*"; }
log_ok() { echo -e "${GREEN}[PASS]${NC} $*"; }
log_fail() { echo -e "${RED}[FAIL]${NC} $*"; }
log_warn() { echo -e "${YELLOW}[WARN]${NC} $*"; }

mkdir -p "$LOG_DIR"
log_info "Logging to: $LOG_DIR"

# ────────────────────────────────────────────────────────────────
# Test 1: Thread-safe initialization
# ────────────────────────────────────────────────────────────────
test_thread_safe_init() {
    log_info "Test 1: Thread-safe initialization"

    # Build test binary
    cargo build --release -p mcp-agent-mail-db \
        --features hybrid 2>"$LOG_DIR/build.log" || {
        log_fail "Build failed"
        return 1
    }

    # Run concurrent init test
    # This test spawns multiple threads that all try to init the bridge
    cargo test --release -p mcp-agent-mail-db \
        test_concurrent_init_no_race \
        -- --nocapture 2>&1 | tee "$LOG_DIR/test1_concurrent_init.log"

    # Check for duplicate init messages
    INIT_COUNT=$(grep -c "Two-tier semantic bridge initialized" "$LOG_DIR/test1_concurrent_init.log" || echo "0")

    if [[ "$INIT_COUNT" -le 1 ]]; then
        log_ok "No duplicate initialization detected (count: $INIT_COUNT)"
        return 0
    else
        log_fail "Duplicate initialization detected (count: $INIT_COUNT)"
        return 1
    fi
}

# ────────────────────────────────────────────────────────────────
# Test 2: Quality embedding fallback
# ────────────────────────────────────────────────────────────────
test_quality_fallback() {
    log_info "Test 2: Quality embedding fallback"

    # Create test database
    TEST_DB="$LOG_DIR/test_quality_fallback.db"

    # Run quality fallback test suite
    cargo test --release -p mcp-agent-mail-search-core \
        test_search_mixed_quality_docs \
        test_refinement_excludes_non_quality_docs \
        test_quality_coverage_metric \
        -- --nocapture 2>&1 | tee "$LOG_DIR/test2_quality_fallback.log"

    # Verify no zero-vector assertions
    if grep -q "quality embedding should be non-zero" "$LOG_DIR/test2_quality_fallback.log"; then
        log_fail "Zero-vector quality embedding detected"
        return 1
    fi

    log_ok "Quality fallback tests passed"
    return 0
}

# ────────────────────────────────────────────────────────────────
# Test 3: Progressive refinement
# ────────────────────────────────────────────────────────────────
test_progressive_refinement() {
    log_info "Test 3: Progressive refinement"

    # Run progressive refinement test suite
    cargo test --release -p mcp-agent-mail-search-core \
        test_progressive_yields_initial_and_refined \
        test_fast_only_skips_refinement \
        test_initial_latency_under_5ms \
        -- --nocapture 2>&1 | tee "$LOG_DIR/test3_progressive.log"

    # Extract latency metrics
    INITIAL_LATENCY=$(grep -oP 'initial latency.*?(\d+)ms' "$LOG_DIR/test3_progressive.log" | grep -oP '\d+' | head -1 || echo "0")

    if [[ "$INITIAL_LATENCY" -lt 5 ]]; then
        log_ok "Initial latency acceptable: ${INITIAL_LATENCY}ms < 5ms"
    else
        log_warn "Initial latency high: ${INITIAL_LATENCY}ms >= 5ms"
    fi

    log_ok "Progressive refinement tests passed"
    return 0
}

# ────────────────────────────────────────────────────────────────
# Test 4: Integration with search service
# ────────────────────────────────────────────────────────────────
test_search_service_integration() {
    log_info "Test 4: Search service integration"

    # Start test server
    TEST_PORT=9876
    TEST_DB="$LOG_DIR/test_integration.db"

    cargo run --release -p mcp-agent-mail-server -- \
        --db "$TEST_DB" \
        --port "$TEST_PORT" \
        &>/dev/null &
    SERVER_PID=$!

    # Wait for server to start
    sleep 2

    # Create test data
    curl -s -X POST "http://localhost:$TEST_PORT/api/ensure-project" \
        -H "Content-Type: application/json" \
        -d '{"human_key": "test-project"}' > /dev/null

    curl -s -X POST "http://localhost:$TEST_PORT/api/register-agent" \
        -H "Content-Type: application/json" \
        -d '{"project_key": "test-project", "program": "test", "model": "test-model", "name": "test-agent"}' > /dev/null

    # Send test message
    curl -s -X POST "http://localhost:$TEST_PORT/api/send-message" \
        -H "Content-Type: application/json" \
        -d '{"project_key": "test-project", "sender_name": "test-agent", "to": ["test-agent"], "subject": "Test semantic search", "body_md": "This is a test message for two-tier semantic search hardening verification."}' > /dev/null

    # Wait for indexing
    sleep 1

    # Search and verify
    SEARCH_RESULT=$(curl -s -X POST "http://localhost:$TEST_PORT/api/search-messages" \
        -H "Content-Type: application/json" \
        -d '{"project_key": "test-project", "query": "semantic search hardening", "limit": 10}')

    echo "$SEARCH_RESULT" > "$LOG_DIR/test4_search_result.json"

    # Cleanup
    kill "$SERVER_PID" 2>/dev/null || true

    # Verify result
    if echo "$SEARCH_RESULT" | grep -q "Test semantic search"; then
        log_ok "Search service integration passed"
        return 0
    else
        log_fail "Search did not return expected result"
        return 1
    fi
}

# ────────────────────────────────────────────────────────────────
# Main
# ────────────────────────────────────────────────────────────────
main() {
    local failed=0

    log_info "Starting Two-Tier Search Hardening E2E Tests"
    log_info "=========================================="

    test_thread_safe_init || ((failed++))
    test_quality_fallback || ((failed++))
    test_progressive_refinement || ((failed++))
    # test_search_service_integration || ((failed++))  # Optional, requires server

    log_info "=========================================="
    if [[ $failed -eq 0 ]]; then
        log_ok "All tests passed!"
        exit 0
    else
        log_fail "$failed test(s) failed"
        exit 1
    fi
}

main "$@"
```

